def perceive(data):
    text = data if isinstance(data, str) else str(data.get("text", ""))
    low = text.lower()
    out = {}
    if ("request" in low or "interrogator" in low or "production" in low) and        ("served" in low or "propounded" in low or "filed" in low):
        out["request_served"] = True
    for token in low.replace(",", " ").split():
        if token.startswith("day="):
            try:
                out["day"] = int(token.split("=", 1)[1])
            except (ValueError, KeyError):
                pass
    return out
